proof fn phi_1_repeatn_parse_length_external_body<C: SecureSpecCombinator>(c: &RepeatN<C>, s: Seq<u8>, n: int, vs: Seq<C::Type>)
    requires
        c.requires(),
        c.spec_parse(s) == Some((n, vs)),
    ensures
        0 <= n <= s.len(),
{
    c.lemma_parse_length(s);
}

proof fn phi_2_inner_parse_length_external_body<C: SecureSpecCombinator>(c: &C, s: Seq<u8>, n: int, v: C::Type)
    requires
        c.requires(),
        c.spec_parse(s) == Some((n, v)),
    ensures
        0 <= n <= s.len(),
{
    c.lemma_parse_length(s);
}

proof fn phi_4_parse_consumed_monotone<C: SecureSpecCombinator>(
    c: &RepeatN<C>, s: Seq<u8>,
    n1: usize, n2: usize,
    m1: int, m2: int,
    vs1: Seq<C::Type>, vs2: Seq<C::Type>,
)
    requires
        c.requires(),
        n1 <= n2,
        c.spec_parse_helper(s, n1) == Some((m1, vs1)),
        c.spec_parse_helper(s, n2) == Some((m2, vs2)),
    ensures
        m1 <= m2,
    decreases n2,
{
    if n1 == n2 {
    } else {
        if let Some((m_prev, vs_prev)) = c.spec_parse_helper(s, (n2 - 1) as usize) {
            phi_4_parse_consumed_monotone(c, s, n1, (n2 - 1) as usize, m1, m_prev, vs1, vs_prev);
            c.0.lemma_parse_length(s.skip(m_prev as int));
        }
    }
}

proof fn phi_5_parse_result_length_equals_count<C: SecureSpecCombinator>(c: &RepeatN<C>, s: Seq<u8>, n: usize, m: int, vs: Seq<C::Type>)
    requires
        c.spec_parse_helper(s, n) == Some((m, vs)),
    ensures
        vs.len() == n,
    decreases n,
{
    if n == 0 {
    } else {
        if let Some((m_prev, vs_prev)) = c.spec_parse_helper(s, (n - 1) as usize) {
            phi_5_parse_result_length_equals_count(c, s, (n - 1) as usize, m_prev, vs_prev);
        }
    }
}
